-- =============================================================================
-- KumoDent / Aoikumo Schema — Supabase Migration
-- Generated from: all Aoikumo Sales, Payment, Inventory, Customer,
--   Appointment, Employee, Clinical, Commission and Other report CSVs (109 reports)
-- =============================================================================

-- Enable UUID extension
create extension if not exists "uuid-ossp";

-- =============================================================================
-- REFERENCE / MASTER TABLES
-- =============================================================================

-- Outlets (branches)
-- Source: Sales By Outlet Report, Sales Detailed Report
create table if not exists outlets (
  id           uuid primary key default uuid_generate_v4(),
  name         text not null unique,
  code         text,
  address1     text,
  address2     text,
  city         text,
  state        text,
  postcode     text,
  country      text default 'Malaysia',
  phone        text,
  email        text,
  is_active    boolean default true,
  created_at   timestamptz default now(),
  updated_at   timestamptz default now()
);

-- Employees / Staff
-- Source: Sales By Employee Report, Employee Listing Report
-- Captured columns: Employee ID, Name, Identification #, Email, Date of Birth,
--   Gender, Contact #, Role, Position, Start Date, Main Outlet, Secondary Outlet,
--   Country, State, City, kumoSan Access, Web Access, Bookable, Online Bookable, Username
create table if not exists employees (
  id                  uuid primary key default uuid_generate_v4(),
  employee_code       text unique,              -- "Employee ID" from report
  name                text not null,
  identification_no   text,
  email               text,
  date_of_birth       date,
  gender              text,
  contact_no          text,
  role                text,                     -- Therapist, Consultant, Admin, etc.
  position            text,
  start_date          date,
  main_outlet_id      uuid references outlets(id),
  secondary_outlet_id uuid references outlets(id),
  country             text default 'Malaysia',
  state               text,
  city                text,
  username            text,
  kumosan_access      boolean default false,    -- "kumoSan Access?"
  web_access          boolean default false,    -- "Web Access?"
  bookable            boolean default true,     -- "Bookable?"
  online_bookable     boolean default false,    -- "Online Bookable?"
  sales_target        numeric(10,2) default 0,  -- from Sales By Employee
  handson_points      numeric(10,2) default 0,  -- from Sales By Employee
  is_active           boolean default true,
  created_at          timestamptz default now(),
  updated_at          timestamptz default now()
);

-- Services catalogue
-- Source: Service Sales Report, Service Listing by Outlet
create table if not exists services (
  id            uuid primary key default uuid_generate_v4(),
  sku           text not null unique,
  name          text not null,
  category      text,
  type          text default 'Standard',        -- Standard, Premium
  duration_min  int,
  price         numeric(10,2) not null default 0,
  is_active     boolean default true,
  created_at    timestamptz default now(),
  updated_at    timestamptz default now()
);

-- Products catalogue
-- Source: Item Sales Report, Stock Movement Report
create table if not exists products (
  id            uuid primary key default uuid_generate_v4(),
  sku           text not null unique,
  name          text not null,
  brand         text,
  category      text,
  uom           text default 'PCS',             -- Unit of Measure
  cost_price    numeric(10,2) default 0,
  sell_price    numeric(10,2) default 0,
  stock_qty     numeric(10,3) default 0,
  reorder_level numeric(10,3) default 0,
  supplier_id   uuid,
  is_active     boolean default true,
  created_at    timestamptz default now(),
  updated_at    timestamptz default now()
);

-- Mix & Match package definitions
-- Source: Mix and Match Sales Report
create table if not exists mix_match_packages (
  id            uuid primary key default uuid_generate_v4(),
  sku           text not null unique,           -- "SKU" (MM-001)
  name          text not null,                  -- "MM Name"
  total_price   numeric(10,2) default 0,
  sessions      int default 0,                  -- total sessions included
  is_active     boolean default true,
  created_at    timestamptz default now()
);

-- Credit voucher schemes
-- Source: Sales Voucher Use Report, Credit Voucher Sales Report
create table if not exists voucher_schemes (
  id            uuid primary key default uuid_generate_v4(),
  name          text not null,                  -- "Voucher Name"
  batch_no      int,                            -- "Voucher Batch"
  voucher_type  text default 'MYR',             -- MYR or %
  value         numeric(10,2) default 0,        -- "Voucher Value"
  expiry_date   date,
  is_active     boolean default true,
  created_at    timestamptz default now()
);

-- Discount schemes
-- Source: Sales Discount Use Report
create table if not exists discount_schemes (
  id            uuid primary key default uuid_generate_v4(),
  name          text not null,                  -- "Discount Name"
  type          text default 'PERCENTAGE',      -- PERCENTAGE, FIXED
  value         numeric(10,2) default 0,
  assignment    text,                           -- who can assign
  is_active     boolean default true,
  created_at    timestamptz default now()
);

-- Suppliers
-- Source: Supplier Listing Report, Purchase Orders Report
create table if not exists suppliers (
  id            uuid primary key default uuid_generate_v4(),
  name          text not null,
  code          text unique,
  contact       text,
  email         text,
  phone         text,
  address       text,
  is_active     boolean default true,
  created_at    timestamptz default now()
);

-- =============================================================================
-- CUSTOMER TABLE
-- =============================================================================

-- Customers / Members
-- Source: Sales Detailed, Customer Reports, Customer Lead Generation
-- Captured columns: ID, Customer, Membership, Phone, Total Appt, BP, BP Wallet,
--   Cash wallet, Collection, CV Total, LP, CV Wallet, Sales, Case note, Follow Up,
--   Medical Certificate, E-Form, Documents, Records
create table if not exists customers (
  id                    uuid primary key default uuid_generate_v4(),
  membership_no         text not null unique,   -- PK from Aoikumo (e.g. ANB260001)
  name                  text not null,
  first_name            text,
  last_name             text,
  salutation            text,                   -- Mr, Ms, Mrs, Dr
  gender                text,
  identification_no     text,                   -- IC / Passport
  phone                 text,
  phone2                text,
  email                 text,
  date_of_birth         date,
  membership_type       text default 'No Membership', -- GOLD MEMBER, VIP MEMBER, etc.
  home_outlet_id        uuid references outlets(id),
  consultant_id         uuid references employees(id),
  -- Address
  address1              text,
  address2              text,
  city                  text,
  state                 text,
  postcode              text,
  country               text default 'Malaysia',
  -- Wallet / loyalty balances (denormalised for fast read)
  cash_wallet_balance   numeric(10,2) default 0,
  beauti_points_balance numeric(10,2) default 0,
  credit_voucher_balance numeric(10,2) default 0,
  loyalty_points_balance numeric(10,2) default 0,
  -- Preferences
  source                text,                   -- Walk In, Referral, ADS, Online Booking
  preferred_language    text default 'English',
  opt_in_notifications  boolean default true,
  opt_in_marketing      boolean default true,
  is_vip                boolean default false,
  -- Medical
  allergies             text,
  medical_notes         text,
  -- Stats (denormalised, updated by trigger or job)
  total_appointments    int default 0,
  total_sales           numeric(10,2) default 0,
  -- Meta
  join_date             date,
  created_at            timestamptz default now(),
  updated_at            timestamptz default now()
);

-- =============================================================================
-- APPOINTMENTS
-- =============================================================================

-- Appointments
-- Source: Appointments Detailed Report
-- Columns: Date, Time, Booking Ref, Customer, Membership #, Phone,
--   Service, Staff/Therapist, Chair/Room, Duration, Status, Payment Status, Notes
create table if not exists appointments (
  id               uuid primary key default uuid_generate_v4(),
  booking_ref      text not null unique,         -- e.g. BREF-001001
  customer_id      uuid references customers(id),
  customer_name    text,                          -- denormalised
  customer_phone   text,
  membership_no    text,
  service_id       uuid references services(id),
  service_name     text,
  service_code     text,
  employee_id      uuid references employees(id), -- therapist/dentist
  employee_name    text,
  outlet_id        uuid references outlets(id),
  chair            text,                          -- chair / room
  start_time       timestamptz not null,
  end_time         timestamptz,
  duration_min     int,
  status           text default 'pending',        -- pending, confirmed, completed, cancelled, no-show
  payment_status   text default 'unpaid',         -- unpaid, paid, partial
  tags             text[],
  notes            text,
  case_notes       text,
  follow_up        text,
  created_by       text,
  created_at       timestamptz default now(),
  updated_at       timestamptz default now()
);

-- Appointment changes log
-- Source: Appointments Change Report
create table if not exists appointment_changes (
  id               uuid primary key default uuid_generate_v4(),
  appointment_id   uuid references appointments(id),
  booking_ref      text,
  changed_at       timestamptz,
  changed_by       text,
  field_changed    text,
  old_value        text,
  new_value        text,
  reason           text
);

-- =============================================================================
-- SALES (CORE TRANSACTION TABLES)
-- =============================================================================

-- Sales Orders (header)
-- Source: Sales Detailed Report (27 columns — full schema)
create table if not exists sales (
  id               uuid primary key default uuid_generate_v4(),
  so_number        text not null unique,          -- SO/1/000356 (PK from Aoikumo)
  type             text default 'STORE',          -- STORE, CV, BP, CW, MM, EVENT, ADMIN
  outlet_id        uuid references outlets(id),
  outlet_name      text,
  customer_id      uuid references customers(id),
  customer_name    text,
  identification_no text,
  customer_phone   text,
  membership_no    text,
  membership_type  text,
  payee_origin     text default 'STORE',
  -- Financials (all match Aoikumo Sales Detailed columns)
  sub_total        numeric(10,2) default 0,
  voucher          numeric(10,2) default 0,       -- CV applied
  discount         numeric(10,2) default 0,       -- discount applied
  cw               numeric(10,2) default 0,       -- cash wallet used
  cw_tax           numeric(10,2) default 0,
  gross            numeric(10,2) default 0,       -- sub_total - discount - voucher - cw
  tax_value        numeric(10,2) default 0,       -- SST/GST
  cancelled        numeric(10,2) default 0,
  cw_cancelled     numeric(10,2) default 0,
  rounding         numeric(10,2) default 0,
  nett             numeric(10,2) default 0,       -- net payable
  payment_to_date  numeric(10,2) default 0,
  outstanding      numeric(10,2) default 0,
  -- Staff
  sales_person     text,
  processed_by     text,
  created_by       text,
  -- Notes
  sales_notes      text,
  remarks          text,
  -- Status
  status           text default 'completed',      -- completed, cancelled, pending
  -- Timestamps
  sale_date        date,
  sale_time        time,
  created_at       timestamptz default now(),
  updated_at       timestamptz default now()
);

-- Sale Items (lines)
-- Source: Item Sales Report, Service Sales Report
create table if not exists sale_items (
  id             uuid primary key default uuid_generate_v4(),
  so_number      text not null references sales(so_number),
  sku            text,
  item_name      text not null,
  brand          text,
  type           text,                             -- Product, Service, CV, BP, MM, Promo, Bundle
  quantity       int default 1,
  unit_price     numeric(10,2) default 0,
  unit_discount  numeric(10,2) default 0,
  total_price    numeric(10,2) default 0,
  uom            text default 'SESSION',
  redeemed       int default 0,
  cancelled      boolean default false,
  created_at     timestamptz default now()
);

-- Payments
-- Source: Payment Detailed Report
-- Columns: Date, Time, Invoice #, SO #, Outlet, Customer, Identification #,
--   Phone, Membership #, Type, Payment Method, Amount, Bank, Trace #,
--   Approval Code, Reference #, Outstanding, Processed By
create table if not exists payments (
  id             uuid primary key default uuid_generate_v4(),
  invoice_no     text unique,                     -- INV/1/000356
  so_number      text references sales(so_number),
  outlet_id      uuid references outlets(id),
  customer_name  text,
  identification_no text,
  customer_phone text,
  membership_no  text,
  payment_date   date,
  payment_time   time,
  payment_mode   text,                             -- Cash, Card, Online Transfer, CW, CV, BP
  payment_type   text,                             -- Visa, Mastercard, FPX, e-wallet name
  bank           text,
  amount         numeric(10,2) default 0,
  trace_no       text,
  approval_code  text,
  ref_no         text,
  outstanding    numeric(10,2) default 0,
  payee_origin   text,
  remarks        text,
  processed_by   text,
  created_at     timestamptz default now()
);

-- Sales Cancellations (Credit Notes)
-- Source: Sales Cancellation Report (17 columns — full schema)
create table if not exists cancellations (
  id                   uuid primary key default uuid_generate_v4(),
  cn_number            text not null unique,       -- CN/1/000012
  cn_date              date,
  cn_time              time,
  so_number            text references sales(so_number),
  so_date              date,
  so_time              time,
  cancellation_outlet  text,
  so_creation_outlet   text,
  customer_name        text,
  identification_no    text,
  customer_phone       text,
  amount               numeric(10,2) default 0,
  tax                  numeric(10,2) default 0,
  tax_rate             text default '0%',
  processed_by         text,
  sales_person         text,
  remarks              text,
  created_at           timestamptz default now()
);

-- Discounts Used per line item
-- Source: Sales Discount Use Report (19 columns — full schema)
create table if not exists discounts_used (
  id               uuid primary key default uuid_generate_v4(),
  so_number        text references sales(so_number),
  discount_date    date,
  discount_time    time,
  customer_name    text,
  identification_no text,
  customer_phone   text,
  membership_no    text,
  membership_type  text,
  sku              text,
  item_name        text,
  unit_price       numeric(10,2) default 0,
  unit_discount    numeric(10,2) default 0,
  quantity         int default 1,
  total_price      numeric(10,2) default 0,
  total_discount   numeric(10,2) default 0,
  nett_price       numeric(10,2) default 0,
  discount_name    text,
  assignment       text,
  processed_by     text,
  created_at       timestamptz default now()
);

-- =============================================================================
-- LOYALTY / WALLET TABLES
-- =============================================================================

-- Credit Vouchers
-- Source: Credit Voucher Sales Report, Sales Voucher Use Report
create table if not exists credit_vouchers (
  id             uuid primary key default uuid_generate_v4(),
  cv_number      text not null unique,             -- CV/1/000045
  so_number      text references sales(so_number),
  so_date        date,
  so_time        time,
  cv_name        text,                             -- scheme name
  voucher_batch  int,
  voucher_no     text,                             -- voucher code
  voucher_type   text default 'MYR',
  voucher_value  numeric(10,2) default 0,
  item_redeemed  text,
  paid           numeric(10,2) default 0,
  type           text,                             -- VOUCHER, REDEMPTION
  customer_name  text,
  membership_no  text,
  sales_person   text,
  created_by     text,
  created_at     timestamptz default now()
);

-- Beauti Points transactions
-- Source: Beauti Points Sales Report (12 columns — full schema)
create table if not exists beauti_points (
  id           uuid primary key default uuid_generate_v4(),
  bp_number    text not null unique,               -- BP/1/000088
  so_number    text references sales(so_number),
  so_date      date,
  so_time      time,
  bp_date      date,
  bp_time      time,
  customer_name text,
  identification_no text,
  phone        text,
  membership_no text,
  sales_person text,
  paid_bp      numeric(10,2) default 0,
  created_at   timestamptz default now()
);

-- Cash Wallet transactions
-- Source: Cash Wallet Sales Report (15 columns — full schema)
create table if not exists cash_wallet (
  id             uuid primary key default uuid_generate_v4(),
  so_number      text references sales(so_number),
  cw_date        date,
  cw_time        time,
  type           text,                             -- CW (top-up), CW_USE (redemption)
  outlet_id      uuid references outlets(id),
  customer_name  text,
  membership_no  text,
  membership_type text,
  cw_amount      numeric(10,2) default 0,
  gross          numeric(10,2) default 0,
  nett           numeric(10,2) default 0,
  payment_to_date numeric(10,2) default 0,
  outstanding    numeric(10,2) default 0,
  sales_person   text,
  created_at     timestamptz default now()
);

-- Mix & Match package purchases
-- Source: Mix and Match Sales Report (8 columns summary + detail)
create table if not exists mix_match_sales (
  id               uuid primary key default uuid_generate_v4(),
  so_number        text references sales(so_number),
  package_id       uuid references mix_match_packages(id),
  sku              text,
  mm_name          text,
  quantity         int default 1,
  cancelled_qty    int default 0,
  sales_amount     numeric(10,2) default 0,
  average_sales    numeric(10,2) default 0,
  payment_to_date  numeric(10,2) default 0,
  outstanding      numeric(10,2) default 0,
  customer_name    text,
  membership_no    text,
  purchased_qty    int default 0,                  -- sessions purchased
  redeemed_qty     int default 0,                  -- sessions redeemed
  balance_qty      int default 0,                  -- sessions remaining
  created_at       timestamptz default now()
);

-- =============================================================================
-- INVENTORY
-- =============================================================================

-- Stock movements
-- Source: Stock Movement Report, Stock Movement Detailed Report
create table if not exists stock_movements (
  id             uuid primary key default uuid_generate_v4(),
  movement_date  date,
  movement_time  time,
  product_id     uuid references products(id),
  sku            text,
  product_name   text,
  brand          text,
  category       text,
  outlet_id      uuid references outlets(id),
  movement_type  text,                             -- IN, OUT, ADJUST, TRANSFER
  reference_no   text,                             -- PO#, SO#, or Transfer Order#
  opening_qty    numeric(10,3) default 0,
  in_qty         numeric(10,3) default 0,
  out_qty        numeric(10,3) default 0,
  closing_qty    numeric(10,3) default 0,
  uom            text,
  unit_cost      numeric(10,2) default 0,
  created_by     text,
  created_at     timestamptz default now()
);

-- Purchase Orders
-- Source: Purchase Orders Report
create table if not exists purchase_orders (
  id             uuid primary key default uuid_generate_v4(),
  po_number      text not null unique,
  po_date        date,
  supplier_id    uuid references suppliers(id),
  outlet_id      uuid references outlets(id),
  status         text default 'pending',           -- pending, received, cancelled
  total_amount   numeric(10,2) default 0,
  received_date  date,
  created_by     text,
  remarks        text,
  created_at     timestamptz default now()
);

-- Purchase order lines
create table if not exists purchase_order_items (
  id              uuid primary key default uuid_generate_v4(),
  po_number       text references purchase_orders(po_number),
  product_id      uuid references products(id),
  sku             text,
  product_name    text,
  quantity        numeric(10,3) default 0,
  unit_cost       numeric(10,2) default 0,
  total_cost      numeric(10,2) default 0,
  received_qty    numeric(10,3) default 0,
  created_at      timestamptz default now()
);

-- =============================================================================
-- COMMISSION & INCENTIVES
-- =============================================================================

-- Commission records
-- Source: Commission & Incentive Reports
create table if not exists commissions (
  id               uuid primary key default uuid_generate_v4(),
  commission_month date,                           -- first day of the month
  employee_id      uuid references employees(id),
  employee_name    text,
  outlet_id        uuid references outlets(id),
  services_sales   numeric(10,2) default 0,
  products_sales   numeric(10,2) default 0,
  total_sales      numeric(10,2) default 0,
  services_commission numeric(10,2) default 0,
  products_commission numeric(10,2) default 0,
  total_commission numeric(10,2) default 0,
  incentive        numeric(10,2) default 0,
  payout           numeric(10,2) default 0,
  created_at       timestamptz default now()
);

-- =============================================================================
-- CLINICAL / MEDICAL RECORDS
-- =============================================================================

-- Case Notes
-- Source: Case Notes Report
create table if not exists case_notes (
  id               uuid primary key default uuid_generate_v4(),
  appointment_id   uuid references appointments(id),
  customer_id      uuid references customers(id),
  customer_name    text,
  membership_no    text,
  note_date        date,
  note_time        time,
  content          text,
  employee_id      uuid references employees(id),
  created_by       text,
  created_at       timestamptz default now(),
  updated_at       timestamptz default now()
);

-- Prescriptions
-- Source: Prescription Report
create table if not exists prescriptions (
  id               uuid primary key default uuid_generate_v4(),
  appointment_id   uuid references appointments(id),
  customer_id      uuid references customers(id),
  customer_name    text,
  prescription_date date,
  medication       text,
  dosage           text,
  frequency        text,
  duration         text,
  notes            text,
  prescribed_by    text,
  created_at       timestamptz default now()
);

-- Vaccinations
-- Source: Vaccination Report
create table if not exists vaccinations (
  id               uuid primary key default uuid_generate_v4(),
  customer_id      uuid references customers(id),
  customer_name    text,
  membership_no    text,
  vaccine_name     text,
  batch_no         text,
  administered_date date,
  next_due_date    date,
  administered_by  text,
  outlet_id        uuid references outlets(id),
  created_at       timestamptz default now()
);

-- =============================================================================
-- OTHER OPERATIONAL TABLES
-- =============================================================================

-- Petty Cash
-- Source: Petty Cash Report (Sales Tab)
create table if not exists petty_cash (
  id             uuid primary key default uuid_generate_v4(),
  cash_date      date not null,
  cash_time      time,
  outlet_id      uuid references outlets(id),
  type           text not null,                    -- IN, OUT
  amount         numeric(10,2) not null default 0,
  description    text,
  created_by     text,
  created_at     timestamptz default now()
);

-- Vouchers generated and expiry tracking
-- Source: Voucher Generated & Expiry Report
create table if not exists vouchers_generated (
  id             uuid primary key default uuid_generate_v4(),
  scheme_id      uuid references voucher_schemes(id),
  voucher_name   text,
  voucher_batch  int,
  voucher_no     text not null unique,
  customer_id    uuid references customers(id),
  customer_name  text,
  face_value     numeric(10,2) default 0,
  expiry_date    date,
  status         text default 'active',            -- active, redeemed, expired
  redeemed_date  date,
  redeemed_so    text references sales(so_number),
  created_at     timestamptz default now()
);

-- Other Charges
-- Source: Other Charges Report (17 columns — full schema)
create table if not exists other_charges (
  id             uuid primary key default uuid_generate_v4(),
  so_number      text references sales(so_number),
  charge_date    date,
  charge_time    time,
  type           text,
  outlet_id      uuid references outlets(id),
  customer_name  text,
  identification_no text,
  customer_phone text,
  membership_no  text,
  sku            text,
  item_name      text,
  sales_amount   numeric(10,2) default 0,
  payment_to_date numeric(10,2) default 0,
  outstanding    numeric(10,2) default 0,
  sales_person   text,
  status         text default 'COMPLETED',
  processed_by   text,
  created_at     timestamptz default now()
);

-- =============================================================================
-- INDEXES for performance
-- =============================================================================

create index if not exists idx_sales_so_number        on sales(so_number);
create index if not exists idx_sales_customer_id      on sales(customer_id);
create index if not exists idx_sales_sale_date        on sales(sale_date);
create index if not exists idx_sales_outlet_id        on sales(outlet_id);
create index if not exists idx_sale_items_so_number   on sale_items(so_number);
create index if not exists idx_payments_so_number     on payments(so_number);
create index if not exists idx_payments_invoice_no    on payments(invoice_no);
create index if not exists idx_appointments_customer  on appointments(customer_id);
create index if not exists idx_appointments_start     on appointments(start_time);
create index if not exists idx_appointments_employee  on appointments(employee_id);
create index if not exists idx_customers_membership   on customers(membership_no);
create index if not exists idx_customers_phone        on customers(phone);
