-- =============================================================================
-- UPDATED_AT trigger helper
-- =============================================================================

create or replace function update_updated_at()
returns trigger as $$
begin
  new.updated_at = now();
  return new;
end;
$$ language plpgsql;

create trigger trg_outlets_updated_at
  before update on outlets for each row execute function update_updated_at();
create trigger trg_employees_updated_at
  before update on employees for each row execute function update_updated_at();
create trigger trg_services_updated_at
  before update on services for each row execute function update_updated_at();
create trigger trg_products_updated_at
  before update on products for each row execute function update_updated_at();
create trigger trg_customers_updated_at
  before update on customers for each row execute function update_updated_at();
create trigger trg_appointments_updated_at
  before update on appointments for each row execute function update_updated_at();
create trigger trg_sales_updated_at
  before update on sales for each row execute function update_updated_at();
create trigger trg_case_notes_updated_at
  before update on case_notes for each row execute function update_updated_at();

-- ============================================================
-- FILE: 20260315000001_frontend_compat.sql
-- ============================================================
-- =============================================================================
-- KumoDent Frontend Compatibility Migration
-- Makes the DB work with the frontend data model:
--   1. Creates `patients` table (text PK, matches frontend camelCase→snake_case)
--   2. Adds frontend-friendly columns to `appointments`
--   3. Grants anon / unauthenticated access so the app works without auth
-- =============================================================================

-- ── 1. Patients table (frontend-compatible, text primary key) ─────────────────
create table if not exists patients (
  id                      text primary key,
  member_id               text,
  membership_no           text,
  name                    text,
  first_name              text,
  last_name               text,
  salutation              text,
  gender                  text,
  phone                   text,
  phone2                  text,
  email                   text,
  dob                     text,
  identification_no       text,
  membership_type         text default 'No Membership',
  cash_wallet_balance     numeric(10,2) default 0,
  beauti_points_balance   numeric(10,2) default 0,
  credit_voucher_balance  numeric(10,2) default 0,
  address1                text default '',
  address2                text default '',
  city                    text default '',
  state                   text default '',
  postcode                text default '',
  country                 text default 'Malaysia',
  notes                   text default '',
  dentist                 text,
  consultant              text,
  outlet                  text,
  outlet_id               text,
  source                  text,
  opt_in_notifications    boolean default true,
  opt_in_marketing        boolean default true,
  is_vip                  boolean default false,
  preferred_language      text default 'English',
  case_notes_list         jsonb default '[]'::jsonb,
  join_date               text,
  created_at              timestamptz default now(),
  updated_at              timestamptz default now()
);

alter table patients enable row level security;
-- Allow full anon access (internal clinic app, no public-facing auth required)
drop policy if exists "anon_all" on patients;
create policy "anon_all" on patients for all using (true) with check (true);

-- ── 2. Add frontend-compatible columns to the existing `appointments` table ───
-- These columns use the same names the frontend sends (after snakify).
-- The existing start_time / end_time / customer_* columns remain for backward compat.

alter table appointments
  add column if not exists patient_id    text,
  add column if not exists patient_name  text,
  add column if not exists patient_phone text,
  add column if not exists dentist       text,
  add column if not exists service_code  text,
  add column if not exists outlet_name   text;

-- The `id` column is uuid — we generate proper UUIDs on the frontend now.
-- The `start_time` and `end_time` columns already exist and will receive the values.

-- ── 3. Grant anon full access to tables the frontend actively reads/writes ────
-- appointments
drop policy if exists "anon_all" on appointments;
create policy "anon_all" on appointments for all using (true) with check (true);

-- services (read-only seed, but upsert on init)
drop policy if exists "anon_all" on services;
create policy "anon_all" on services for all using (true) with check (true);

-- sales
drop policy if exists "anon_all" on sales;
create policy "anon_all" on sales for all using (true) with check (true);

-- employees
drop policy if exists "anon_all" on employees;
create policy "anon_all" on employees for all using (true) with check (true);

-- outlets
drop policy if exists "anon_all" on outlets;
create policy "anon_all" on outlets for all using (true) with check (true);

-- customers (existing table — keep accessible too)
drop policy if exists "anon_all" on customers;
create policy "anon_all" on customers for all using (true) with check (true);

