-- ============================================================
-- Line items billed against an appointment (catalog or ad-hoc). IDs are text to
-- match frontend appointment/service keys (e.g. apt-*, svc-*). No FK: local
-- schema may still use uuid PKs on parent tables while the app sends text ids.

create table if not exists public.appointment_billing_items (
  id uuid primary key default gen_random_uuid(),
  appointment_id text not null,
  service_id text,
  item_name text not null,
  quantity integer not null default 1 check (quantity > 0),
  unit_price numeric(10,2) not null default 0,
  total numeric(10,2) generated always as (round((quantity::numeric * unit_price), 2)) stored,
  notes text default '',
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create index if not exists idx_appointment_billing_items_appointment_id
  on public.appointment_billing_items (appointment_id);

alter table public.appointment_billing_items enable row level security;

drop policy if exists "anon_all" on public.appointment_billing_items;
