do $$
begin
  if not exists (
    select 1
    from pg_catalog.pg_attribute a
    where a.attrelid = 'public.employees'::regclass
      and a.attname = 'id'
      and a.attidentity in ('d', 'a')
  ) then
    alter table public.employees
      alter column id add generated by default as identity;
  end if;
end $$;

select setval(
  pg_get_serial_sequence('public.employees', 'id'),
  (select coalesce(max(id), 0) from public.employees)
);

-- ============================================================
-- FILE: 20260331120000_role_permission_flags.sql
-- ============================================================
-- Persist 50-column permission grid in role_permissions.permissions JSONB.
-- Shape: { "all": true } OR { "flags": [ bool × 50 ] } (see rolePermissionPermsFromJson in useStore).

UPDATE role_permissions SET permissions = '{"all": true}'::jsonb WHERE name = 'SYSTEM ADMIN';

UPDATE role_permissions SET permissions = '{"flags":[false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,true,true,true,true,true,true,true,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,true,false,false,false]}'::jsonb WHERE name = 'ACCOUNT';

UPDATE role_permissions SET permissions = '{"flags":[true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,false,true,true,true]}'::jsonb WHERE name = 'ADMIN';

UPDATE role_permissions SET permissions = '{"flags":[true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,false,false,true,false,true,true,false,false,false,false,true,false,true,true,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false]}'::jsonb WHERE name = 'DENTIST';

UPDATE role_permissions SET permissions = '{"flags":[false,false,false,false,true,true,true,true,true,true,true,true,true,true,false,false,false,true,true,false,true,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,true,false,false,false,false]}'::jsonb WHERE name = 'MARKETING';

UPDATE role_permissions SET permissions = '{"flags":[true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,false,false,false,false,false,false,false,false,true,false,true,true,true]}'::jsonb WHERE name = 'PART-TIME';

UPDATE role_permissions SET permissions = '{"flags":[false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false]}'::jsonb WHERE name = 'BEAUTICIAN';

-- ============================================================
-- FILE: 20260331130000_appointments_start_end_columns.sql
-- ============================================================
-- App + exports use "start" / "end". Initial schema used start_time / end_time; rename when needed.
do $$
begin
  if exists (
    select 1 from information_schema.columns
    where table_schema = 'public' and table_name = 'appointments' and column_name = 'start_time'
  ) and not exists (
    select 1 from information_schema.columns
    where table_schema = 'public' and table_name = 'appointments' and column_name = 'start'
  ) then
    alter table public.appointments rename column start_time to start;
  end if;

  if exists (
    select 1 from information_schema.columns
    where table_schema = 'public' and table_name = 'appointments' and column_name = 'end_time'
  ) and not exists (
    select 1 from information_schema.columns
    where table_schema = 'public' and table_name = 'appointments' and column_name = 'end'
  ) then
    alter table public.appointments rename column end_time to "end";
  end if;
end $$;

-- ============================================================
-- FILE: 20260332000001_employees_fks_and_foundation.sql
-- ============================================================
-- One-shot: seed positions/roles (idempotent), wire employees to FKs only (position_id, role_id, outlet_id), drop legacy text columns.
-- Backfill from position/role text runs only if those columns still exist.
-- No demo employee deletes or hard-coded doctor rows — use the Employees UI or your own seed.sql for sample data.

-- ── Reference rows (idempotent) ───────────────────────────────────────────────
insert into public.positions (name)
select v.name
from (
  values
    ('ACCOUNTANT'),
    ('DENTAL ASSISTANT'),
    ('LOCUM DOCTOR'),
    ('MARKETING'),
    ('OPERATION'),
    ('RESIDENT DOCTOR'),
    ('STANDARD')
) as v(name)
where not exists (select 1 from public.positions p where p.name = v.name);

insert into public.role_permissions (name, permissions)
select v.name, v.perms::jsonb
from (
  values
    ('SYSTEM ADMIN', '{"all": true}'),
    ('ACCOUNT', '{}'),
    ('ADMIN', '{}'),
    ('DENTIST', '{}'),
    ('MARKETING', '{}'),
    ('PART-TIME', '{}'),
    ('BEAUTICIAN', '{}')
) as v(name, perms)
where not exists (select 1 from public.role_permissions r where r.name = v.name);

-- ── FK columns ──────────────────────────────────────────────────────────────
alter table public.employees
  add column if not exists position_id text,
  add column if not exists role_id text;

-- Only when legacy text columns exist (older DBs). Current prod had them removed already.
do $legacy$
begin
  if exists (
    select 1 from information_schema.columns
    where table_schema = 'public' and table_name = 'employees' and column_name = 'position'
  ) then
    execute $u$
      update public.employees e
      set position_id = p.id
      from public.positions p
      where e.position_id is null
        and e.position is not null
        and trim(e.position) <> ''
        and upper(trim(p.name)) = upper(trim(e.position))
    $u$;
  end if;
  if exists (
    select 1 from information_schema.columns
    where table_schema = 'public' and table_name = 'employees' and column_name = 'role'
  ) then
    execute $u$
      update public.employees e
      set role_id = r.id
      from public.role_permissions r
      where e.role_id is null
        and e.role is not null
        and trim(e.role) <> ''
        and upper(trim(r.name)) = upper(trim(e.role))
    $u$;
  end if;
end;
$legacy$;

update public.employees
set outlet_id = null
where outlet_id is not null and trim(outlet_id) = '';

-- ── Foreign keys ─────────────────────────────────────────────────────────────
alter table public.employees
  drop constraint if exists employees_outlet_id_fkey,
  drop constraint if exists employees_position_id_fkey,
  drop constraint if exists employees_role_id_fkey;

alter table public.employees
  add constraint employees_outlet_id_fkey
    foreign key (outlet_id) references public.outlets (id) on delete set null,
  add constraint employees_position_id_fkey
    foreign key (position_id) references public.positions (id) on delete set null,
  add constraint employees_role_id_fkey
    foreign key (role_id) references public.role_permissions (id) on delete set null;

create index if not exists idx_employees_position_id on public.employees (position_id);
create index if not exists idx_employees_role_id on public.employees (role_id);

-- ── Remove legacy duplicate labels ──────────────────────────────────────────
alter table public.employees
  drop column if exists position,
  drop column if exists role,
  drop column if exists outlet;

