-- ============================================================
-- FILE: 20260334000001_customers_core_fks_retire_patients.sql
-- ============================================================
-- Core customer model: single public.customers table, FKs to outlets/employees/appointments/sales.
-- Retires public.patients when present (data copy + ID remap). Idempotent-friendly.

-- ── customers: home_outlet_id matches outlets.id (text) ──────────────────────
do $ctype$
begin
  if exists (
    select 1 from information_schema.columns
    where table_schema = 'public' and table_name = 'customers'
      and column_name = 'home_outlet_id' and udt_name = 'uuid'
  ) then
    alter table public.customers
      alter column home_outlet_id type text using (
        case when home_outlet_id is not null then home_outlet_id::text else null end
      );
  end if;
end;
$ctype$;

-- ── customers: consultant = employee integer id (was legacy uuid) ────────────
alter table public.customers drop column if exists consultant_id;
alter table public.customers
  add column consultant_id integer references public.employees(id) on delete set null;

-- ── Optional: migrate patients → customers ───────────────────────────────────
do $mig$
begin
  if exists (
    select 1 from information_schema.tables
    where table_schema = 'public' and table_name = 'patients'
  ) then
    create temporary table pat_cust_map (old_id text primary key, new_id uuid not null unique) on commit drop;

    insert into pat_cust_map (old_id, new_id)
    select p.id, gen_random_uuid() from public.patients p;

    insert into public.customers (
      id, name, first_name, last_name, salutation, gender,
      phone, phone2, email, date_of_birth, identification_no,
      membership_type, membership_no, customer_code,
      home_outlet_id, address1, address2, city, state, postcode, country,
      medical_notes, created_at, updated_at
    )
    select
      m.new_id,
      coalesce(nullif(trim(p.name), ''), 'Unknown'),
      nullif(trim(p.first_name), ''), nullif(trim(p.last_name), ''),
      nullif(trim(p.salutation), ''), nullif(trim(p.gender), ''),
      nullif(trim(p.phone), ''), nullif(trim(p.phone2), ''), nullif(trim(p.email), ''),
      case
        when p.dob is null or trim(p.dob) = '' then null
        when p.dob ~ '^\d{4}-\d{2}-\d{2}' then p.dob::date
        else null
      end,
      nullif(trim(p.identification_no), ''),
      coalesce(nullif(trim(p.membership_type), ''), 'No Membership'),
      nullif(trim(p.membership_no), ''),
      'CUS-' || replace(m.new_id::text, '-', ''),
      nullif(trim(p.outlet_id), ''),
      coalesce(nullif(trim(p.address1), ''), ''), coalesce(nullif(trim(p.address2), ''), ''),
      coalesce(nullif(trim(p.city), ''), ''), coalesce(nullif(trim(p.state), ''), ''),
      coalesce(nullif(trim(p.postcode), ''), ''),
      coalesce(nullif(trim(p.country), ''), 'Malaysia'),
      left(trim(coalesce(p.notes, '') || case when coalesce(trim(p.allergies), '') <> '' then E'\n' || p.allergies else '' end), 10000),
      coalesce(p.created_at, now()), coalesce(p.updated_at, now())
    from public.patients p
    join pat_cust_map m on m.old_id = p.id;

    update public.appointments a
    set customer_id = mp.new_id
    from pat_cust_map mp
    where a.patient_id is not null and trim(a.patient_id::text) = mp.old_id;

    if exists (
      select 1 from information_schema.columns
      where table_schema = 'public' and table_name = 'sales' and column_name = 'patient_id'
    ) then
      execute '
        update public.sales s
        set customer_id = mp.new_id
        from pat_cust_map mp
        where s.patient_id is not null and trim(s.patient_id::text) = mp.old_id';
    end if;

    alter table public.appointments drop column if exists patient_id;
    alter table public.appointments drop column if exists patient_name;
    alter table public.appointments drop column if exists patient_phone;

    if exists (
      select 1 from information_schema.columns
      where table_schema = 'public' and table_name = 'sales' and column_name = 'patient_id'
    ) then
      alter table public.sales drop column patient_id;
    end if;

    drop table public.patients;
  end if;
end;
$mig$;

-- ── sales: customer_id + customer_name (drop legacy patient_name) ─────────────
alter table public.sales add column if not exists customer_id uuid;
alter table public.sales add column if not exists customer_name text;

do $sales$
begin
  if exists (
    select 1 from information_schema.columns
    where table_schema = 'public' and table_name = 'sales' and column_name = 'patient_name'
  ) then
    execute 'update public.sales set customer_name = coalesce(customer_name, patient_name)';
    execute 'alter table public.sales drop column patient_name';
  end if;
end;
$sales$;

alter table public.sales drop column if exists patient_id;

-- ── Clear orphan FK values so constraints can validate ──────────────────────
update public.customers c
set home_outlet_id = null
where c.home_outlet_id is not null
  and not exists (select 1 from public.outlets o where o.id = c.home_outlet_id);

update public.appointments a
set customer_id = null
where a.customer_id is not null
  and not exists (select 1 from public.customers cu where cu.id = a.customer_id);

update public.sales s
set customer_id = null
where s.customer_id is not null
  and not exists (select 1 from public.customers cu where cu.id = s.customer_id);

-- ── Referential integrity (nullable FKs — leads / legacy rows still OK) ───────
alter table public.appointments drop constraint if exists appointments_customer_id_fkey;
alter table public.appointments
  add constraint appointments_customer_id_fkey
  foreign key (customer_id) references public.customers(id) on delete set null;

alter table public.customers drop constraint if exists customers_home_outlet_id_fkey;
alter table public.customers
  add constraint customers_home_outlet_id_fkey
  foreign key (home_outlet_id) references public.outlets(id) on delete set null;

alter table public.sales drop constraint if exists sales_customer_id_fkey;
alter table public.sales
  add constraint sales_customer_id_fkey
  foreign key (customer_id) references public.customers(id) on delete set null;

create index if not exists idx_customers_home_outlet on public.customers(home_outlet_id);
create index if not exists idx_customers_phone on public.customers(phone) where phone is not null and trim(phone) <> '';

-- ============================================================
-- FILE: 20260335000001_appointments_uuid_pk_and_relational_fks.sql
-- ============================================================
-- Appointments: uuid PK (was text holding uuid strings); FKs for outlet, service, employee.
-- Children: appointment_billing_items, sales, wa_booking_notes appointment_id → uuid.

alter table public.appointment_billing_items
  drop constraint if exists appointment_billing_items_appointment_id_fkey;

alter table public.sales
  drop constraint if exists sales_appointment_id_fkey;

alter table public.wa_booking_notes
  drop constraint if exists wa_booking_notes_appointment_id_fkey;

update public.appointments
set outlet_id = null
where outlet_id is not null and trim(outlet_id) = '';

update public.appointments
set service_id = null
where service_id is not null and trim(service_id) = '';

-- Cast to text before trim: appointment_id may already be uuid when re-running or after partial apply.
update public.sales
set appointment_id = null
where appointment_id is not null and trim(appointment_id::text) = '';

update public.sales s
set appointment_id = null
where s.appointment_id is not null and trim(s.appointment_id::text) <> ''
  and not exists (
    select 1 from public.appointments a where a.id::text = s.appointment_id::text
  );

update public.wa_booking_notes w
set appointment_id = null
where w.appointment_id is not null and trim(w.appointment_id::text) <> ''
  and not exists (
    select 1 from public.appointments a where a.id::text = w.appointment_id::text
  );

update public.wa_booking_notes
set appointment_id = null
where appointment_id is not null and trim(appointment_id::text) = '';

-- appointment_id is NOT NULL: drop rows that cannot reference an appointment.
delete from public.appointment_billing_items abi
where trim(abi.appointment_id::text) = ''
   or not exists (
    select 1 from public.appointments a where a.id::text = abi.appointment_id::text
  );

-- Orphans block FKs — clear first (matches 20260334000001 pattern).
update public.appointments a
set outlet_id = null
where a.outlet_id is not null
  and not exists (select 1 from public.outlets o where o.id = a.outlet_id);

update public.appointments a
set service_id = null
where a.service_id is not null
  and not exists (select 1 from public.services s where s.id = a.service_id);

update public.appointments a
set employee_id = null
where a.employee_id is not null
  and not exists (select 1 from public.employees e where e.id = a.employee_id);

alter table public.appointments
  alter column id drop default,
  alter column id type uuid using id::uuid,
  alter column id set default gen_random_uuid();

alter table public.appointment_billing_items
  alter column appointment_id type uuid using appointment_id::uuid;

alter table public.sales
  alter column appointment_id type uuid using appointment_id::uuid;

alter table public.wa_booking_notes
  alter column appointment_id type uuid using appointment_id::uuid;

alter table public.appointment_billing_items
  drop constraint if exists appointment_billing_items_appointment_id_fkey;
alter table public.appointment_billing_items
  add constraint appointment_billing_items_appointment_id_fkey
  foreign key (appointment_id) references public.appointments(id) on delete cascade;

alter table public.sales
  drop constraint if exists sales_appointment_id_fkey;
alter table public.sales
  add constraint sales_appointment_id_fkey
  foreign key (appointment_id) references public.appointments(id) on delete set null;

alter table public.wa_booking_notes
  drop constraint if exists wa_booking_notes_appointment_id_fkey;
alter table public.wa_booking_notes
  add constraint wa_booking_notes_appointment_id_fkey
  foreign key (appointment_id) references public.appointments(id) on delete set null;

alter table public.appointments drop constraint if exists appointments_outlet_id_fkey;
alter table public.appointments
  add constraint appointments_outlet_id_fkey
  foreign key (outlet_id) references public.outlets(id) on delete set null;

alter table public.appointments drop constraint if exists appointments_service_id_fkey;
