-- ============================================================
-- FILE: 20260401000001_sequential_customer_codes.sql
-- ============================================================
-- Migrate UUID-based customer_codes to sequential CUS-000001 format.
-- Skips customers that already have a valid sequential code (CUS- followed by digits only).
-- New numbers start after the highest existing sequential code.

with max_existing as (
  -- Find the highest number among already-sequential codes
  select coalesce(max(regexp_replace(customer_code, '\D', '', 'g')::bigint), 0) as max_num
  from public.customers
  where customer_code ~ '^CUS-\d+$'
),
to_fix as (
  -- Only customers whose code is NOT already sequential (i.e. contains hex/uuid chars)
  select id, created_at,
         row_number() over (order by created_at, id) as rn
  from public.customers
  where customer_code !~ '^CUS-\d+$'
),
numbered as (
  select tf.id,
         'CUS-' || lpad((me.max_num + tf.rn)::text, 6, '0') as new_code
  from to_fix tf
  cross join max_existing me
)
update public.customers c
set customer_code = n.new_code
from numbered n
where c.id = n.id;

-- Also update the denormalised customer_code on appointments
update public.appointments a
set customer_code = c.customer_code
from public.customers c
where a.customer_id = c.id
  and a.customer_code is distinct from c.customer_code;

