-- FILE: 20260404000001_outlets_cleanup_reseed.sql
-- ============================================================
-- =============================================================================
-- Outlets: convert from text PK to uuid PK, keep it simple.
-- =============================================================================

-- ── 1. Drop FK constraints referencing outlets(id) ──────────────────────────
alter table public.employees     drop constraint if exists employees_outlet_id_fkey;
alter table public.customers     drop constraint if exists customers_home_outlet_id_fkey;
alter table public.appointments  drop constraint if exists appointments_outlet_id_fkey;

-- ── 2. Null out all outlet references (old text IDs will be invalid) ────────
update public.employees     set outlet_id = null       where outlet_id is not null;
update public.customers     set home_outlet_id = null   where home_outlet_id is not null;
update public.appointments  set outlet_id = null        where outlet_id is not null;

-- ── 3. Drop and recreate outlets with uuid PK ──────────────────────────────
drop table if exists public.outlets cascade;

create table public.outlets (
  id         uuid primary key default gen_random_uuid(),
  code       text,
  name       text not null,
  brand_id   text not null default 'brand-big-dental',
  is_active  boolean default true,
  created_at timestamptz default now(),
  updated_at timestamptz default now()
);

alter table public.outlets enable row level security;
drop policy if exists "anon_all" on public.outlets;
create policy "anon_all" on public.outlets for all using (true) with check (true);

create trigger trg_outlets_updated_at
  before update on public.outlets for each row execute function update_updated_at();

-- ── 4. Convert outlet_id columns from text → uuid ──────────────────────────
alter table public.employees
  alter column outlet_id type uuid using null;

alter table public.customers
  alter column home_outlet_id type uuid using null;

do $atype$
begin
  if exists (
    select 1 from information_schema.columns
    where table_schema = 'public' and table_name = 'appointments'
      and column_name = 'outlet_id' and udt_name <> 'uuid'
  ) then
    alter table public.appointments
      alter column outlet_id type uuid using null;
  end if;
end;
$atype$;

-- ── 5. Re-add FK constraints ────────────────────────────────────────────────
alter table public.employees
  add constraint employees_outlet_id_fkey
  foreign key (outlet_id) references public.outlets(id) on delete set null;

alter table public.customers
  add constraint customers_home_outlet_id_fkey
  foreign key (home_outlet_id) references public.outlets(id) on delete set null;

alter table public.appointments
  add constraint appointments_outlet_id_fkey
  foreign key (outlet_id) references public.outlets(id) on delete set null;

