-- 2. Drop employees.outlet_id (replaced by junction table)
-- 3. rooms column on outlets (per-outlet treatment rooms)
-- =============================================================================

-- ── 1. Junction table ─────────────────────────────────────────────────────────
create table if not exists public.employee_outlets (
