-- ============================================================
-- FILE: 20260406000002_positions_roles_uuid_pks.sql
-- ============================================================
-- Convert positions.id and role_permissions.id from TEXT to UUID.
-- Some existing rows have non-UUID IDs (e.g. "role-1", "pos-1") so we replace
-- them with real UUIDs first, then convert the column type.
-- Also ensure positions has a status column for Active/Inactive toggling.

-- ── 1. Drop FK constraints on employees that reference these tables ──────────
alter table public.employees
  drop constraint if exists employees_position_id_fkey,
  drop constraint if exists employees_role_id_fkey;

-- ── 2. Replace non-UUID ids with real UUIDs ─────────────────────────────────
-- For each non-UUID position id, generate a new UUID and update employees too.
do $$
declare
  r record;
  new_id text;
begin
  for r in
    select id from public.positions
    where id !~ '^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$'
  loop
    new_id := gen_random_uuid()::text;
    update public.employees set position_id = new_id where position_id = r.id;
    update public.positions set id = new_id where id = r.id;
  end loop;

  for r in
    select id from public.role_permissions
    where id !~ '^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$'
  loop
    new_id := gen_random_uuid()::text;
    update public.employees set role_id = new_id where role_id = r.id;
    update public.role_permissions set id = new_id where id = r.id;
  end loop;
end $$;

-- Also clear any employee FK values that don't match an existing row
update public.employees set position_id = null
  where position_id is not null
    and position_id !~ '^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$';

update public.employees set role_id = null
  where role_id is not null
    and role_id !~ '^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$';

-- ── 3. Convert positions.id TEXT → UUID ─────────────────────────────────────
alter table public.positions
  alter column id set default null;

alter table public.positions
  alter column id type uuid using id::uuid;

alter table public.positions
  alter column id set default gen_random_uuid();

-- ── 4. Convert role_permissions.id TEXT → UUID ──────────────────────────────
alter table public.role_permissions
  alter column id set default null;

alter table public.role_permissions
  alter column id type uuid using id::uuid;

alter table public.role_permissions
  alter column id set default gen_random_uuid();

-- ── 5. Convert FK columns on employees TEXT → UUID ──────────────────────────
alter table public.employees
  alter column position_id type uuid using position_id::uuid;

alter table public.employees
  alter column role_id type uuid using role_id::uuid;

-- ── 6. Re-add foreign key constraints ───────────────────────────────────────
alter table public.employees
  add constraint employees_position_id_fkey
    foreign key (position_id) references public.positions (id) on delete set null,
  add constraint employees_role_id_fkey
    foreign key (role_id) references public.role_permissions (id) on delete set null;

-- ── 7. Ensure positions has a status column ─────────────────────────────────
alter table public.positions
  add column if not exists status text not null default 'Active';

-- ── 8. Drop stale employee_count column (now computed from employees) ───────
alter table public.positions
  drop column if exists employee_count;

