-- ============================================================
-- FILE: 20260406000004_employee_shifts.sql
-- ============================================================
-- Employee working-hours / shift templates.
-- Each row represents a recurring (or one-off) shift for an employee on a given weekday.

create table if not exists public.employee_shifts (
  id            uuid primary key default gen_random_uuid(),
  employee_id   uuid not null references public.employees(id) on delete cascade,
  outlet_id     uuid not null references public.outlets(id) on delete cascade,
  day_of_week   int  not null check (day_of_week between 0 and 6),  -- 0=Mon .. 6=Sun
  shift_date    date,             -- set when repeat_type='none' (the specific date)
  start_time    time not null default '09:00',
  end_time      time not null default '18:00',
  is_overnight  boolean default false,
  repeat_type   text default 'weekly' check (repeat_type in ('none','weekly')),
  repeat_end    date,            -- NULL = ongoing (only used when repeat_type='weekly')
  breaks        jsonb default '[]',  -- [{start:"HH:mm", end:"HH:mm"}, ...]
  remarks       text default '',
  is_active     boolean default true,
  created_at    timestamptz default now(),
  updated_at    timestamptz default now()
);

create index if not exists idx_employee_shifts_employee on public.employee_shifts(employee_id);
create index if not exists idx_employee_shifts_outlet   on public.employee_shifts(outlet_id);

alter table public.employee_shifts enable row level security;
drop policy if exists "anon_all" on public.employee_shifts;
create policy "anon_all" on public.employee_shifts for all using (true) with check (true);

