-- FILE: 20260407000002_ensure_case_notes_table.sql
-- ============================================================
-- Ensure case_notes table exists (may have been missed if initial migration was partial)
create table if not exists case_notes (
  id               uuid primary key default gen_random_uuid(),
  appointment_id   uuid references appointments(id),
  customer_id      uuid references customers(id),
  customer_name    text,
  membership_no    text,
  note_date        date,
  note_time        time,
  content          text,
  employee_id      uuid references employees(id),
  created_by       text,
  created_at       timestamptz default now(),
  updated_at       timestamptz default now()
);

-- Ensure RLS
alter table case_notes enable row level security;

-- Ensure RLS policy (drop + recreate to be idempotent)
do $$
begin
  if not exists (
    select 1 from pg_policies where tablename = 'case_notes' and policyname = 'Authenticated full access'
  ) then
    create policy "Authenticated full access" on case_notes for all using (auth.role() = 'authenticated');
  end if;
end $$;

-- Ensure updated_at trigger
create or replace function update_updated_at() returns trigger as $$
begin new.updated_at = now(); return new; end;
$$ language plpgsql;

drop trigger if exists trg_case_notes_updated_at on case_notes;
create trigger trg_case_notes_updated_at
  before update on case_notes for each row execute function update_updated_at();

-- Reload PostgREST schema cache
notify pgrst, 'reload schema';

